insert into locations (id, title, slug, category, latitude, longitude, address, short_description, bloom_status, access_type, is_active, is_featured)
values
  (gen_random_uuid(), 'Branding Beach Club', 'branding-beach-club', 'food', 52.237246, 4.422416, 'Kon. Astrid Boulevard 105, 2202 BD Noordwijk', 'Topbeachclub aan de boulevard met open haard, glazen paviljoen, verse ceviche en een onverslaanbare strandvibe. Vroeg reserveren sterk aanbevolen.', null, 'public_access', true, false),
  (gen_random_uuid(), 'Tulum', 'tulum', 'food', 52.252846, 4.435362, 'Zeereep 104, 2202 NW Noordwijk', 'Sfeervol beach restaurant met tropische inrichting en zeezicht. Warm personeel, ruim terras en een gevarieerd menu van bowls tot sushi.', null, 'public_access', true, false),
  (gen_random_uuid(), 'Strandclub Witsand', 'strandclub-witsand', 'food', 52.252018, 4.434521, 'Zeereep 103, 2202 NW Noordwijk', 'Geliefde strandclub met verse burrata, truffelfriet en fijne sfeer. Populair bij dagjesmensen na Keukenhof. Reservering aanbevolen in het seizoen.', null, 'public_access', true, false),
  (gen_random_uuid(), 'Papa Ito Fusion Gastrobar', 'papa-ito-fusion-gastrobar', 'food', 52.242734, 4.42995, 'De Grent 22, 2202 EL Noordwijk', 'Bijzondere fusiongastrobar met hoogwaardige rolletjes en cocktails. Fijnproeverij in een sfeervol interieur. Hoge score, klein en exclusief.', null, 'public_access', true, false),
  (gen_random_uuid(), 'De Smaakmaker', 'de-smaakmaker', 'food', 52.243312, 4.432949, 'Hoofdstraat 63, 2202 EV Noordwijk', 'Gezellige lunchroom op de Hoofdstraat met verse broodjes, iced coffee en heerlijke appeltaart. Hondvriendelijk en wifi beschikbaar.', null, 'public_access', true, false),
  (gen_random_uuid(), 'Alexander Beach Club', 'alexander-beach-club', 'food', 52.244728, 4.428082, 'Koningin Wilhelmina Boulevard afrit 10, 2202 GR Noordwijk', 'Uitgebreid beach restaurant met veel zitmogelijkheden binnen en buiten, origineel menu en vriendelijke bediening. Goede prijs-kwaliteitverhouding.', null, 'public_access', true, false),
  (gen_random_uuid(), 'Café de Rosser', 'cafe-de-rosser', 'food', 52.242331, 4.430208, 'De Grent 10, 2202 EL Noordwijk', 'Knusse kroeg met uitstekende steak, eerlijke prijzen en oprecht gastvrij personeel. Geliefd bij locals en bezoekers. Sfeervolle avondplek.', null, 'public_access', true, false),
  (gen_random_uuid(), 'Bij De Duinen', 'bij-de-duinen', 'food', 52.268806, 4.469445, 'Duindamseweg 8, 2204 AS Noordwijk', 'Gerenoveerd restaurant aan de duinrand met groot terras. Populaire ribs, poke bowls en viszaken. Mooie combinatie natuur en horeca.', null, 'public_access', true, false),
  (gen_random_uuid(), 'Lunchhuis Ons Thuis', 'lunchhuis-ons-thuis', 'food', 52.234589, 4.445781, 'Kerkstraat 43A, 2201 KL Noordwijk', 'Knus lunchhuis in Noordwijk-Binnen met huisgemaakte taarten, uitstekende koffie en verse tosti''s. Gezellig, betaalbaar en sfeervol.', null, 'public_access', true, false),
  (gen_random_uuid(), 'Langs Berg en Dal', 'langs-berg-en-dal', 'food', 52.28323, 4.486209, 'Langevelderlaan 22, 2204 BD Noordwijk', 'Familiaire pannenkoekrestaurant bij de duinen met speeltuin. Ideaal tussenstop op de fiets- of autoroute. Breed aanbod en snelle bediening.', null, 'public_access', true, false),
  (gen_random_uuid(), 'Como & Co', 'como-co', 'food', 52.278701, 4.502272, 'Boekhorsterweg 18, 2211 AL Noordwijkerhout', 'Populair restaurant aan het meer met ruim terras en warme sfeer. Het hele jaar door gezellig. Breed menu, vriendelijk personeel en mooie locatie.', null, 'public_access', true, false),
  (gen_random_uuid(), 'De Voliëre', 'de-voliere', 'food', 52.28233, 4.503648, 'Duinschooten 12, 2211 ZC Noordwijkerhout', 'Sfeervol restaurant aan het meer met open keuken en sharing-concept. Uitzonderlijk mooi terras en interieur. Een van de beste eettips in de regio.', null, 'public_access', true, false),
  (gen_random_uuid(), 'Brasserie Op Dorp', 'brasserie-op-dorp', 'food', 52.262925, 4.493409, 'Dorpsringweg 1a, 2211 GA Noordwijkerhout', 'Karaktervolle brasserie op het dorpsplein met typisch Hollandse sfeer en zicht op de witte kerk. Fietsers en tulpenroute-bezoekers van harte welkom.', null, 'public_access', true, false),
  (gen_random_uuid(), 'Wapen van Noordwijkerhout', 'wapen-van-noordwijkerhout', 'food', 52.262822, 4.49292, 'Dorpsstraat 14, 2211 GC Noordwijkerhout', 'Klassiek dorpsrestaurant met hotel aan de Dorpsstraat. Uitstekende schnitzel en vegetarische opties. Warme bediening en goede prijs-kwaliteit.', null, 'public_access', true, false),
  (gen_random_uuid(), 'Brownies&downies Noordwijkerhout', 'brownies-downies-noordwijkerhout', 'food', 52.262668, 4.492713, 'Dorpsstraat 20, 2211 GC Noordwijkerhout', 'Inclusief lunchcafé met hartelijke bediening, lekker eten en fijne brownies. Positieve sfeer en goed voor een snelle lunch tussendoor.', null, 'public_access', true, false),
  (gen_random_uuid(), 'De Ruigenhoek', 'de-ruigenhoek', 'food', 52.291866, 4.526336, 'Herenweg 444, 2211 VJ Noordwijkerhout', 'Karakteristiek restaurant aan de tulpenroute met groot terras en ruime parkeergelegenheid. Geliefd bij fietsers na de bollenvelden. Huisdieren welkom.', null, 'public_access', true, false),
  (gen_random_uuid(), 'Lunchbreek', 'lunchbreek', 'food', 52.292036, 4.578675, 'Hoofdstraat 107, 2181 EC Hillegom', 'Populaire lunchroom met dagverse broodjes, bagels en koffie. Vlees van de lokale slager, vers gebakken brood. Hoge score en breed publiek.', null, 'public_access', true, false),
  (gen_random_uuid(), 'Bar-Restaurant Het Alternatief', 'bar-restaurant-het-alternatief', 'food', 52.294541, 4.580496, 'Hoofdstraat 29, 2181 EA Hillegom', 'Veelzijdig restaurant op de Hoofdstraat met zonnig terras. Sterke tapasplank, asiatische salades en goede wijnkaart. Vriendelijk en attent personeel.', null, 'public_access', true, false),
  (gen_random_uuid(), 'Eetcafé Zomerzorg', 'eetcafe-zomerzorg', 'food', 52.291897, 4.583765, 'Meerlaan 70, 2181 BT Hillegom', 'Gezellig lokaal eetcafé met goede bierkeuze en smakelijk eten. Vrij parkeren bij Jumbo. Ideaal voor een ontspannen stop tijdens de tulpenroute.', null, 'public_access', true, false),
  (gen_random_uuid(), 'De Soete Suikerbol', 'de-soete-suikerbol', 'food', 52.294381, 4.580103, 'Hoofdstraat 34a, 2181 ED Hillegom', 'Gezellig familiair restaurant met pannenkoeken, speelhoek en ruime porties. Eigen speelkeuken voor kinderen. Goede stop voor gezinnen op de route.', null, 'public_access', true, false),
  (gen_random_uuid(), 'De Bollenstreek Lunch & More', 'de-bollenstreek-lunch-more', 'food', 52.289772, 4.577635, 'Hoofdstraat 198, 2182 ER Hillegom', 'Nieuw, snel stijgend restaurant met uitstekende bediening en grote porties. Huisgemaakte desserts en fijne sfeer. Kleine parkeertip nodig.', null, 'public_access', true, false),
  (gen_random_uuid(), 'Evi Deli', 'evi-deli', 'food', 52.259566, 4.553752, 'Heereweg 218, 2161 BR Lisse', 'Verborgen parel aan de Heereweg met uitstekende sandwiches, lokale bieren en huisgemaakte appeltaart. Gastvrij, betaalbaar en hoog gewaardeerd.', null, 'public_access', true, false),
  (gen_random_uuid(), 'De Heerekamer Lisse', 'de-heerekamer-lisse', 'food', 52.260299, 4.554372, 'Heereweg 200, 2161 BP Lisse', 'Sfeervolle brasserie aan de Heereweg met geweldig brood, gyoza en verse gerechten. Glutenvrij-vriendelijk en huisdieren welkom op het terras.', null, 'public_access', true, false),
  (gen_random_uuid(), 'Funky Moose Restaurant', 'funky-moose-restaurant', 'food', 52.26028, 4.555456, 'Kanaalstraat 22, 2161 JL Lisse', 'Eigenzinnig restaurant met houtskoolgrillgerechten en kleurrijke cocktails. Hartelijk onthaal, mooie presentaties en goede prijs-kwaliteit.', null, 'public_access', true, false),
  (gen_random_uuid(), 'Restaurant De Vier Seizoenen', 'restaurant-de-vier-seizoenen', 'food', 52.259514, 4.553681, 'Heereweg 224, 2161 BR Lisse', 'Sfeervolle brasserie met B&B aan het dorpsplein. Verse oesters, eend en rib-eye. In het seizoen met bloemenmenu. Fijn voor een rustig diner.', null, 'public_access', true, false),
  (gen_random_uuid(), 'Brasserie Cafetaria Family Lisse', 'brasserie-cafetaria-family-lisse', 'food', 52.260264, 4.559274, 'Blokhuis 24, 2161 EW Lisse', 'Ruime en gezinsvriendelijke brasserie in Lisse. Eenvoudig maar lekker, met vriendelijk personeel. Populaire tussenstop op drukke bollenveldendagen.', null, 'public_access', true, false),
  (gen_random_uuid(), 'Barista Cafe Lisse', 'barista-cafe-lisse', 'food', 52.260378, 4.559175, 'Blokhuis 20, 2161 EW Lisse', 'Gezellig koffiecafé met wifi, verse eitjes en uitgebreide koffiekaart. Ideale stop voor fietsers en wandelaars. Meerdere rave reviews van Keukenhof-bezoekers.', null, 'public_access', true, false),
  (gen_random_uuid(), 'IJssalon MIN12', 'ijssalon-min12', 'food', 52.259949, 4.554408, 'Heereweg 201, 2161 BE Lisse', 'Geliefde ijssalon met brede smakenkeuze waaronder de populaire mini-15 proefschaaltjes. Vriendelijk personeel en redelijke prijzen.', null, 'public_access', true, false),
  (gen_random_uuid(), 'Hofboerderij', 'hofboerderij', 'food', 52.266925, 4.539466, 'Keukenhof 1, 2161 AN Lisse', 'Charmant restaurant op het landgoed Keukenhof. Warme chocolademelk en kroketten na een natte fietstocht. Rustig, groen en sfeervolle omgeving.', null, 'public_access', true, false),
  (gen_random_uuid(), 'ENJOY Sassenheim', 'enjoy-sassenheim', 'food', 52.225356, 4.520468, 'Hoofdstraat 167a, 2171 BB Sassenheim', 'Uitstekend restaurant aan de Hoofdstraat met hoge kwaliteit, vriendelijk jong personeel en heerlijk eten. Ruim en ontspannen. Sterk aanbevolen.', null, 'public_access', true, false),
  (gen_random_uuid(), 'Op Eigen Wijze', 'op-eigen-wijze', 'food', 52.22807, 4.52442, 'Hoofdstraat 265, 2171 BD Sassenheim', 'Populair restaurant met heerlijke spareribs, cocktails en desserts. Aardige sfeer en goede bediening. Regelmatig vollopen, reservering verstandig.', null, 'public_access', true, false),
  (gen_random_uuid(), 'Brasserie Hemels', 'brasserie-hemels', 'food', 52.227222, 4.525556, 'Voorhavenkwartier 51, 2171 HW Sassenheim', 'Lichte brasserie bij het Voorhavenkwartier met uitsmijters, fried chicken en goede koffie. Snel en vriendelijk bediend. Ideaal voor lunchdrukte.', null, 'public_access', true, false),
  (gen_random_uuid(), 'Café Restaurant De Voogd', 'cafe-restaurant-de-voogd', 'food', 52.228121, 4.524533, 'Hoofdstraat 267B, 2171 BD Sassenheim', 'Gezellig eetcafé met brede bierselectie, gebakken camembert en hartelijke ontvangst. Vintage interieur, knusse atmosfeer. Goed voor een borrel.', null, 'public_access', true, false),
  (gen_random_uuid(), 'Welgelegen Kitchen & Drinks', 'welgelegen-kitchen-drinks', 'food', 52.228166, 4.490423, 'Jacoba van Beierenweg 90, 2215 KZ Voorhout', 'Gezellig restaurant met terras, hondvriendelijk buiten, geweldige mosterdsoep en vriendelijk personeel. Fijne prijs-kwaliteit en leuke pub-sfeer.', null, 'public_access', true, false),
  (gen_random_uuid(), 'Brasserie Jill''s', 'brasserie-jill-s', 'food', 52.220533, 4.480243, 'Herenstraat 74, 2215 KJ Voorhout', 'Kleine brasserie met indrukwekkende spareribs en gezellige sfeer. Hoge score en tevreden vaste klanten. Kleine kaart, grote kwaliteit.', null, 'public_access', true, false),
  (gen_random_uuid(), 'Lunchroom Ons Genoegen', 'lunchroom-ons-genoegen', 'food', 52.221579, 4.481883, 'Herenstraat 100, 2215 KK Voorhout', 'Gezellige lunchroom met huisgemaakt gevoel, grote porties en vriendelijke bediening. Bekend bij locals en toeristen. Ook glutenvrij beschikbaar.', null, 'public_access', true, false),
  (gen_random_uuid(), 'Cheers! Voorhout', 'cheers-voorhout', 'food', 52.221722, 4.48198, 'Herenstraat 106, 2215 KK Voorhout', 'Aangenaam café-restaurant met terras en cocktailbar. Verrast door menu-kwaliteit ondanks pub-uitstraling. Goed voor lunch en een aperitief.', null, 'public_access', true, false),
  (gen_random_uuid(), 'Het Alternatief Eten & Drinken', 'het-alternatief-eten-drinken', 'food', 52.220286, 4.479624, 'Herenstraat 62, 2215 KJ Voorhout', 'Uniek restaurant met internationale keukenstijlen in één interieur. Vijfsterrenservice en smaakvol eten. Bijzondere belevenis in Voorhout.', null, 'public_access', true, false),
  (gen_random_uuid(), '''t Soldaatje', 't-soldaatje', 'food', 52.237655, 4.505725, 'Jacoba van Beierenweg 150, 2215 KX Voorhout', 'Huiselijk volksrestaurant met lage prijzen, hartelijke bediening en heerlijke crème brûlée. Ideaal voor groepen na een fietstocht. Geen creditcard.', null, 'public_access', true, false),
  (gen_random_uuid(), 'Cafetaria de Zilk', 'cafetaria-de-zilk', 'food', 52.301464, 4.546539, 'Regenvlietweg 22, 2191 BC De Zilk', 'Nieuwe, prachtig ingerichte cafetaria in het hart van De Zilk. Verse friet, burgers en snacks. Open keuken, speelhoek buiten en hartelijk onthaal.', null, 'public_access', true, false)
